#pragma once\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\n// Correctly register under baseline scope; all namespace issues resolved\\\\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\\\\\\\\n    // Process each row of A, column of B\\\\\n    for (size_t i = 0; i < M; ++i) {\\\\\\\\n        for (size_t j = 0; j < K; j += 16) {\\\\\\\\n            float row_accum[16] = {0.0f};\\\\\n            // For each output cell, preload and accumulate\\\n            for (size_t k = 0; k < K; ++k) {\\\\\\\\\\\n                uint32_t bval = B[k * (K/32) + j/32];\\\\\n                int32_t bit = (int32_t)((bval >> (j % 32)) & 1u);\\\\\n                float sign = bit ? 1.0f : -1.0f;\\\\\n                row_accum[k % 16] += A[i * K + k] * sign;\\\\\n            }\\\\\\n            // Write accumulated terms\\\\\n            for (size_t kp = 0; kp < 16; ++kp) {\\\\\\\\n                size_t out_idx = j + kp;\\\\ if (out_idx < K) C[i * K + out_idx] = row_accum[kp];\\n            }\\n        }\\n    }\\n}